/** LegendPTS_bonus(b, pointsSpent) = round(pointsSpent * LEGEND_TALENTS[b].coeff). */
export function legendPtsBonus(b, pointsSpent) {
  const row = LEGEND_TALENTS[b];
  if (!row) throw new Error(`LegendPTS_bonus(${b}): id ${b} is a "filler" row (40-49) or out of range 0-39`);
  return Math.round(Number(pointsSpent ?? 0) * row.coeff);
}

/** LegendTalent_MaxLV(b, gridNodeRawLevels) — gridNodeRawLevels: a lookup `(node) => number` for
 *  Grid_Bonus(node,1) (see bonuses/research.mjs::gridLevel, or pass ctx there). The four clusters
 *  below are the ONLY ids whose max level depends on the Research Grid; everyone else is flat. */
const MAXLV_CLUSTERS = [
  { ids: [2, 13, 3, 18, 5], node: 130 },
  { ids: [9, 23, 33, 1, 16], node: 131 },
  { ids: [20, 31, 19, 27, 8], node: 132 },
  { ids: [34, 30, 29, 6, 26], node: 152 },
];
export function legendTalentMaxLv(b, gridNodeRawLevel) {
  const row = LEGEND_TALENTS[b];
  if (!row) throw new Error(`LegendTalent_MaxLV(${b}): id ${b} is a "filler" row (40-49) or out of range 0-39`);
  const cluster = MAXLV_CLUSTERS.find((c) => c.ids.includes(b));
  if (!cluster) return row.maxLvBase;
  if (typeof gridNodeRawLevel !== "function") {
    throw new Error(`LegendTalent_MaxLV(${b}) needs Grid_Bonus(${cluster.node},1) — pass gridNodeRawLevel(node)`);
  }
  return Math.floor(gridNodeRawLevel(cluster.node) + row.maxLvBase);
}
